import Navbar from '../shared/Navbar';
import Footer from '../shared/Footer';

export default function Pricing() {
  const plans = [
    { name: 'Hot Desk', price: 699, features: ['Any seat access', 'High-speed Wi‑Fi', 'Tea/Coffee'] },
    { name: 'Dedicated Desk', price: 1099, features: ['Personal desk', 'Locker access', '24x7 access'] },
    { name: 'Private Office', price: 1999, features: ['Private cabin', 'Meeting credits', 'Onsite reception'] },
    { name: 'Meeting Rooms', price: 499, features: ['Hourly booking', 'AV + Projector', 'Reception support'] }
  ];

  return (
    <div className="min-h-screen flex flex-col bg-white">
      <Navbar />
      <main className="flex-1 max-w-7xl mx-auto px-6 py-10">
        <h1 className="text-3xl font-bold text-gray-900">Simple, transparent pricing</h1>
        <p className="mt-2 text-gray-600">Flexible options for individuals, startups, and enterprises.</p>
        <div className="mt-8 grid grid-cols-1 md:grid-cols-4 gap-6">
          {plans.map((p) => (
            <div key={p.name} className="p-6 rounded-2xl border border-gray-100 shadow-card">
              <div className="text-lg font-semibold text-gray-900">{p.name}</div>
              <div className="mt-2 text-2xl font-bold text-gray-900">₹{p.price}<span className="text-base text-gray-500">/day</span></div>
              <ul className="mt-4 space-y-2 text-sm text-gray-600">
                {p.features.map((f) => (
                  <li key={f}>• {f}</li>
                ))}
              </ul>
              <a href="/search" className="mt-6 inline-flex items-center justify-center h-10 w-full rounded-lg bg-brand-600 text-white font-semibold hover:bg-brand-700 transition">Get started</a>
            </div>
          ))}
        </div>

        <div className="mt-12 p-8 rounded-2xl border border-gray-100">
          <div className="text-xl font-semibold text-gray-900">Enterprise solutions</div>
          <p className="mt-1 text-gray-600">Custom floors, branding, and security. Scale with dedicated support.</p>
          <a href="/contact" className="mt-4 inline-flex items-center justify-center h-11 px-6 rounded-lg bg-gray-900 text-white font-semibold hover:bg-black">Talk to sales</a>
        </div>
      </main>
      <Footer />
    </div>
  );
}
